const handleImageUpload = async () => {
    // ... image picking logic ...

    if (result.canceled) {
      return;
    }

    const selectedAsset = result.assets[0];
    if (!selectedAsset) {
      console.error("No asset selected.");
      return;
    }

    const timestamp = new Date().getTime();
    const filename = `image_${timestamp}.jpg`;
    const imagePath = FileSystem.documentDirectory + 'uploaded_images/' + filename;

    try {
      await FileSystem.makeDirectoryAsync(FileSystem.documentDirectory + 'uploaded_images/', { intermediates: true });
      await FileSystem.copyAsync({
        from: selectedAsset.uri,
        to: imagePath,
      });

      Alert.alert("Image uploaded", `Image saved to ${imagePath}`);
      loadUploadedImages();
    } catch (error) {
      console.error("Error uploading image:", error);
      Alert.alert("Error", "Failed to upload image");
    }
  };

  const loadUploadedImages = async () => {
    const directoryPath = FileSystem.documentDirectory + 'uploaded_images/';
    try {
      const dirInfo = await FileSystem.getInfoAsync(directoryPath);
      if (!dirInfo.exists) {
        await FileSystem.makeDirectoryAsync(directoryPath, { intermediates: true });
      }

      const images = await FileSystem.readDirectoryAsync(directoryPath);
      setUploadedImages(images.map(image => directoryPath + image));
    } catch (error) {
      console.error("Error loading images:", error);
    }
  };
```

